SELECT d.nature, d.cnt, o.short_def FROM (SELECT nature, count(*) as cnt FROM read_parquet('data/poi_source/zone_d_activite_ou_d_interet.parquet') WHERE categorie = 'Santé' GROUP BY nature) d LEFT JOIN (SELECT name as obj_name, substring(definition, 1, 120) as short_def FROM read_parquet('data/ontologie/bdtopo_objects.parquet') WHERE parent_db_name = 'zone_d_activite_ou_d_interet') o ON d.nature = o.obj_name ORDER BY d.cnt DESC;
